UPDATE words SET example_en_2 = 'The liver is the largest internal organ in the body.', example_ko_2 = '간은 신체에서 가장 큰 내부 장기예요.', example_en_3 = 'He donated one of his organs to save a stranger''s life.', example_ko_3 = '그는 낯선 사람의 생명을 구하기 위해 장기 하나를 기증했어요.', example_en_4 = 'Each organ in the body has a specific and vital role.', example_ko_4 = '신체의 각 장기는 특정하고 중요한 역할을 가지고 있어요.', example_en_5 = 'Organ transplant surgery has saved millions of lives.', example_ko_5 = '장기 이식 수술은 수백만 명의 생명을 구했어요.' WHERE id = 'w_body_B2_27';
