UPDATE words SET example_en_2 = 'Scientists examined the structure of the protein closely.', example_ko_2 = '과학자들은 단백질의 구조를 면밀히 조사했어요.', example_en_3 = 'The internal structure of the eye is surprisingly intricate.', example_ko_3 = '눈의 내부 구조는 놀라울 정도로 복잡해요.', example_en_4 = 'The class learned about the structure of the cell membrane.', example_ko_4 = '수업에서 세포막의 구조를 배웠어요.', example_en_5 = 'A strong internal structure is essential for healthy bones.', example_ko_5 = '건강한 뼈를 위해서는 강한 내부 구조가 필수적이에요.' WHERE id = 'w_body_B2_29';
UPDATE words SET example_en_2 = 'The doctor noticed abnormal cell growth in the sample.', example_ko_2 = '의사는 샘플에서 비정상적인 세포 성장을 발견했어요.', example_en_3 = 'The test came back showing abnormal results.', example_ko_3 = '검사 결과 비정상적인 수치가 나왔어요.', example_en_4 = 'Abnormal breathing patterns can indicate a medical problem.', example_ko_4 = '비정상적인 호흡 패턴은 의학적 문제를 나타낼 수 있어요.', example_en_5 = 'The X-ray showed an abnormal shadow near the lung.', example_ko_5 = 'X레이에서 폐 근처에 비정상적인 그림자가 나타났어요.' WHERE id = 'w_body_B2_30';
UPDATE words SET example_en_2 = 'Her muscles began to degenerate without regular use.', example_ko_2 = '규칙적으로 사용하지 않자 그녀의 근육이 퇴화하기 시작했어요.', example_en_3 = 'The disease can cause nerve cells to degenerate.', example_ko_3 = '그 질병은 신경 세포를 퇴화시킬 수 있어요.', example_en_4 = 'His vision began to degenerate in his sixties.', example_ko_4 = '그의 시력은 60대에 퇴화하기 시작했어요.', example_en_5 = 'The spinal discs can degenerate over years of heavy lifting.', example_ko_5 = '척추 디스크는 수년간의 무거운 물건 들기로 퇴화할 수 있어요.' WHERE id = 'w_body_B2_31';
UPDATE words SET example_en_2 = 'Stem cells can regenerate damaged tissue in the body.', example_ko_2 = '줄기세포는 신체의 손상된 조직을 재생할 수 있어요.', example_en_3 = 'Liver cells can regenerate after minor damage.', example_ko_3 = '간세포는 경미한 손상 후 재생될 수 있어요.', example_en_4 = 'The treatment aimed to help the nerves regenerate.', example_ko_4 = '그 치료는 신경이 재생되도록 돕는 것을 목표로 했어요.', example_en_5 = 'Researchers are studying how to help cartilage regenerate.', example_ko_5 = '연구자들은 연골이 재생되는 방법을 연구하고 있어요.' WHERE id = 'w_body_B2_32';
