UPDATE words SET example_en_2 = 'The hippocampus is sensitive to stress hormones.', example_ko_2 = '해마는 스트레스 호르몬에 민감해요.', example_en_3 = 'She had a smaller hippocampus due to long-term stress.', example_ko_3 = '그녀는 장기적인 스트레스로 인해 해마가 더 작아졌어요.', example_en_4 = 'The hippocampus allows us to navigate familiar places.', example_ko_4 = '해마는 우리가 익숙한 장소를 탐색할 수 있게 해줘요.', example_en_5 = 'New experiences help stimulate the hippocampus.', example_ko_5 = '새로운 경험은 해마를 자극하는 데 도움이 돼요.' WHERE id = 'w_body_C1_29';
