UPDATE words SET example_en_2 = 'The neurological assessment revealed no serious damage.', example_ko_2 = '신경학적 평가에서 심각한 손상은 발견되지 않았어요.', example_en_3 = 'She experienced neurological symptoms after the fall.', example_ko_3 = '그녀는 넘어진 후 신경학적 증상을 경험했어요.', example_en_4 = 'The disease had a clear neurological component.', example_ko_4 = '그 질병에는 뚜렷한 신경학적 요소가 있었어요.', example_en_5 = 'Early neurological intervention can improve outcomes significantly.', example_ko_5 = '조기 신경학적 개입은 결과를 크게 개선할 수 있어요.' WHERE id = 'w_body_C1_31';
UPDATE words SET example_en_2 = 'She was diagnosed with a gastrointestinal disorder.', example_ko_2 = '그녀는 위장 장애 진단을 받았어요.', example_en_3 = 'The gastrointestinal tract runs from mouth to anus.', example_ko_3 = '위장관은 입부터 항문까지 이어져요.', example_en_4 = 'Stress can have strong effects on gastrointestinal health.', example_ko_4 = '스트레스는 위장 건강에 강한 영향을 미칠 수 있어요.', example_en_5 = 'She followed a diet to manage her gastrointestinal symptoms.', example_ko_5 = '그녀는 위장 증상을 관리하기 위해 식단을 따랐어요.' WHERE id = 'w_body_C1_32';
UPDATE words SET example_en_2 = 'He rested to allow his musculoskeletal system to recover.', example_ko_2 = '그는 근골격계가 회복될 수 있도록 쉬었어요.', example_en_3 = 'Physiotherapy is used to treat musculoskeletal injuries.', example_ko_3 = '물리치료는 근골격계 부상 치료에 사용돼요.', example_en_4 = 'Musculoskeletal pain is one of the most common workplace issues.', example_ko_4 = '근골격계 통증은 가장 흔한 직장 문제 중 하나예요.', example_en_5 = 'The doctor examined her musculoskeletal health thoroughly.', example_ko_5 = '의사가 그녀의 근골격계 건강을 철저히 검사했어요.' WHERE id = 'w_body_C1_33';
UPDATE words SET example_en_2 = 'Biomechanics explains how the body absorbs impact when running.', example_ko_2 = '생체역학은 달릴 때 신체가 충격을 어떻게 흡수하는지 설명해요.', example_en_3 = 'A biomechanics analysis improved her throwing technique.', example_ko_3 = '생체역학 분석이 그녀의 던지기 기술을 개선했어요.', example_en_4 = 'Engineers use biomechanics to design better prosthetics.', example_ko_4 = '공학자들은 더 좋은 의수족을 설계하기 위해 생체역학을 활용해요.', example_en_5 = 'She studied biomechanics as part of her sports science degree.', example_ko_5 = '그녀는 스포츠 과학 학위 과정의 일환으로 생체역학을 공부했어요.' WHERE id = 'w_body_C1_34';
UPDATE words SET example_en_2 = 'Good kinaesthesia helps musicians play with precision.', example_ko_2 = '좋은 운동감각은 음악가가 정확하게 연주하는 데 도움이 돼요.', example_en_3 = 'Impaired kinaesthesia can make everyday movement difficult.', example_ko_3 = '운동감각이 손상되면 일상적인 움직임이 어려워질 수 있어요.', example_en_4 = 'Ballet training develops strong kinaesthesia in dancers.', example_ko_4 = '발레 훈련은 무용수들에게 강한 운동감각을 발달시켜줘요.', example_en_5 = 'Athletes rely on kinaesthesia to react quickly in sport.', example_ko_5 = '운동선수들은 스포츠에서 빠르게 반응하기 위해 운동감각에 의존해요.' WHERE id = 'w_body_C1_35';

