UPDATE words SET example_en_2 = 'Epigenetics shows that lifestyle choices can affect gene expression.', example_ko_2 = '후성유전학은 생활 방식 선택이 유전자 발현에 영향을 줄 수 있음을 보여줘요.', example_en_3 = 'Research in epigenetics has changed how we think about inheritance.', example_ko_3 = '후성유전학 연구는 우리가 유전에 대해 생각하는 방식을 바꿨어요.', example_en_4 = 'Stress may leave epigenetic marks that affect future generations.', example_ko_4 = '스트레스는 미래 세대에 영향을 미치는 후성유전학적 흔적을 남길 수 있어요.', example_en_5 = 'She specialised in epigenetics during her doctoral research.', example_ko_5 = '그녀는 박사 연구 중에 후성유전학을 전공했어요.' WHERE id = 'w_body_C2_01';
UPDATE words SET example_en_2 = 'Neuroplasticity means the brain can recover from certain injuries.', example_ko_2 = '신경 가소성은 뇌가 특정 부상에서 회복할 수 있음을 의미해요.', example_en_3 = 'She used neuroplasticity exercises to improve her memory.', example_ko_3 = '그녀는 기억력을 향상시키기 위해 신경 가소성 운동을 활용했어요.', example_en_4 = 'Neuroplasticity is greatest in early childhood.', example_ko_4 = '신경 가소성은 유아기에 가장 활발해요.', example_en_5 = 'The discovery of neuroplasticity changed neuroscience profoundly.', example_ko_5 = '신경 가소성의 발견은 신경과학을 근본적으로 바꿨어요.' WHERE id = 'w_body_C2_02';
UPDATE words SET example_en_2 = 'A phenotype results from a combination of genes and environment.', example_ko_2 = '표현형은 유전자와 환경의 조합에서 비롯돼요.', example_en_3 = 'The same genotype can produce a different phenotype.', example_ko_3 = '같은 유전자형이라도 다른 표현형을 만들어낼 수 있어요.', example_en_4 = 'Scientists studied how temperature affected the plant phenotype.', example_ko_4 = '과학자들은 온도가 식물 표현형에 어떤 영향을 미치는지 연구했어요.', example_en_5 = 'Height is a complex phenotype influenced by many genes.', example_ko_5 = '키는 많은 유전자의 영향을 받는 복잡한 표현형이에요.' WHERE id = 'w_body_C2_03';
