UPDATE words SET example_en_2 = 'Neurodegeneration in Parkinson''s disease affects movement control.', example_ko_2 = '파킨슨병의 신경 퇴행은 운동 조절에 영향을 미쳐요.', example_en_3 = 'Research aims to slow the process of neurodegeneration.', example_ko_3 = '연구는 신경 퇴행 과정을 늦추는 것을 목표로 해요.', example_en_4 = 'Early diagnosis can sometimes delay neurodegeneration.', example_ko_4 = '조기 진단은 때로는 신경 퇴행을 지연시킬 수 있어요.', example_en_5 = 'She dedicated her career to studying neurodegeneration.', example_ko_5 = '그녀는 신경 퇴행 연구에 자신의 경력을 바쳤어요.' WHERE id = 'w_body_C2_12';
